import static org.junit.jupiter.api.Assertions.assertEquals;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.ExtendedBufferedReader;
import org.apache.commons.csv.Lexer;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class LexerMapNullToDisabledTest {

    private Lexer lexer;
    private Method mapNullToDisabledMethod;

    @BeforeEach
    void setUp() throws NoSuchMethodException {
        // Create a mock CSVFormat and ExtendedBufferedReader as they are required by Lexer constructor
        CSVFormat format = Mockito.mock(CSVFormat.class);
        ExtendedBufferedReader in = Mockito.mock(ExtendedBufferedReader.class);

        // Create an anonymous subclass of Lexer because Lexer is abstract
        lexer = new Lexer(format, in) {
            @Override
            Token nextToken(Token reusableToken) {
                return null;
            }
        };

        // Access private method mapNullToDisabled using reflection
        mapNullToDisabledMethod = Lexer.class.getDeclaredMethod("mapNullToDisabled", Character.class);
        mapNullToDisabledMethod.setAccessible(true);
    }

    @Test
    void testMapNullToDisabledWithNull() throws InvocationTargetException, IllegalAccessException {
        // When input is null, should return DISABLED character '\ufffe'
        char result = (char) mapNullToDisabledMethod.invoke(lexer, (Character) null);
        assertEquals('\ufffe', result);
    }

    @Test
    void testMapNullToDisabledWithNonNull() throws InvocationTargetException, IllegalAccessException {
        // When input is non-null, should return the char value of Character
        Character input = 'a';
        char result = (char) mapNullToDisabledMethod.invoke(lexer, input);
        assertEquals('a', result);

        input = '\n';
        result = (char) mapNullToDisabledMethod.invoke(lexer, input);
        assertEquals('\n', result);

        input = '\0';
        result = (char) mapNullToDisabledMethod.invoke(lexer, input);
        assertEquals('\0', result);
    }
}
